  "Altas Capacidades",
  "Dislexia / DEA",
  "Medidas Nivel II (Apoyo ordinario)",
  "Medidas Nivel III (Apoyo específico)",
  "Desconocimiento del idioma",
  "Problemas de conducta",
  "Discapacidad motora"
];

const METHODOLOGIES = [
