            <p className="text-xs text-amber-800">
              Necesitas una clave de <strong>Gemini 1.5 o 2.0</strong>. Puedes obtenerla gratis en <a href="https://aistudio.google.com/" target="_blank" className="underline font-bold">Google AI Studio</a>.
            </p>
          </div>
        </div>

        <div className="p-6 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
          <button 
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
          >
            Cancelar
          </button>
          <button 
            onClick={handleSave}
            className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-lg shadow-md transition-all"
          >
            {isSaved ? <CheckCircle className="w-4 h-4" /> : null}
            {isSaved ? 'Guardado' : 'Guardar Cambios'}
          </button>
        </div>
      </div>
    </div>
  );
};

