import { GoogleGenAI } from "@google/genai";
import { DocType, TeacherContext, CurriculumAnalysis } from "../types";

// Función para obtener el cliente de IA con la mejor clave disponible
const getAiClient = () => {
  const manualKey = localStorage.getItem('GEMINI_API_KEY');
  const apiKey = manualKey || process.env.API_KEY;

  if (!apiKey) {
    throw new Error("No se ha configurado ninguna API KEY. Por favor, configúrala en el icono de ajustes.");
  }

  return new GoogleGenAI({ apiKey });
};

const SYSTEM_INSTRUCTION = `
Eres un experto pedagogo y jefe de departamento con amplia experiencia en normativa educativa (LOMLOE) y diseño curricular.
Tu objetivo es redactar documentos oficiales precisos basándote en el currículum oficial (PDF) y el contexto proporcionado.
Debes seguir estrictamente la estructura de Markdown solicitada para que el sistema pueda procesar los campos.
Usa un lenguaje técnico, inclusivo y profesional.
IMPORTANTE: Debes escribir el documento ÚNICA Y EXCLUSIVAMENTE en el idioma solicitado por el usuario.
`;

export const analyzePdfStructure = async (pdfBase64: string): Promise<CurriculumAnalysis> => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: `Analiza este PDF del currículum oficial.
          Extrae la siguiente información estructurada en JSON:
          1. "subject": Nombre probable de la Asignatura.
          2. "grade": Curso/Nivel académico.
          3. "competencies": Una lista (array de strings) con los TÍTULOS de las Competencias Específicas relevantes.
          4. "blocks": Una lista (array de strings) con los nombres de los Bloques de Saberes Básicos.

          Devuelve SOLO el JSON raw.` }
        ]
      },
      config: { 
        responseMimeType: "application/json" 
      }
    });

    let text = response.text || "{}";
    const parsed = JSON.parse(text);
    return {
      subject: parsed.subject || "",
      grade: parsed.grade || "",
      competencies: parsed.competencies || [],
      blocks: parsed.blocks || []
    };
  } catch (e) {
    console.error("Error analyzing PDF", e);
    return { subject: "", grade: "", competencies: [], blocks: [] };
  }
};

export const generateEducationalDocument = async (
  pdfBase64: string,
  context: TeacherContext,
  docType: DocType
): Promise<string> => {
  const ai = getAiClient();
  let prompt = "";
  const needsString = [...context.selectedNeeds, context.otherNeeds].filter(Boolean).join(", ");
  const methodologiesString = context.methodologyPreference.join(", ");
  const langInstruction = `EL DOCUMENTO DEBE ESTAR ESCRITO ÍNTEGRAMENTE EN: ${context.language}.`;

  if (docType === DocType.PROPUESTA) {
    prompt = `
      ${langInstruction}
      Genera una **PROPUESTA PEDAGÓGICA DE DEPARTAMENTO**.
      Usa exactamente estos encabezados de nivel 2:

      # PROPUESTA PEDAGÓGICA: ${context.subject}
      ## 1. Concreción Curricular
      Detalla competencias específicas y criterios del PDF vinculados a ${context.gradeLevel}.
      ## 2. Metodología y Estrategias
      Basadas en: ${methodologiesString}.
      ## 3. Evaluación
      Instrumentos, criterios de calificación y temporalización (basado en ${context.weeklyHours}h/semana).
      ## 4. Atención a la Diversidad
      Medidas específicas para: ${needsString}.
    `;
  } else {
    prompt = `
      ${langInstruction}
      Genera ${context.numberOfSAs} **SITUACIONES DE APRENDIZAJE** detalladas para ${context.subject} (${context.gradeLevel}).

      PARA CADA SITUACIÓN DE APRENDIZAJE, debes usar EXACTAMENTE esta estructura y etiquetas:

      ## SITUACIÓN DE APRENDIZAJE: [Título Sugerente]

      **Contexto:**
      | Personal | Educativo | Social | Profesional |
      | :--- | :--- | :--- | :--- |
      | [Descripción corta] | [Descripción corta] | [Descripción corta] | [Descripción corta] |

      **Descripción / Justificación:**
      [Escribe aquí la justificación pedagógica y el reto o producto final esperado]

      **Relación con los retos del s.XXI y los ODS:**
      [Escribe aquí la vinculación con ODS]

      **Competencias Específicas y Criterios de Evaluación vinculados:**
      [Cita las competencias específicas del PDF que se trabajan]

      **Saberes Básicos:**
      [Lista los saberes del PDF involucrados]

      **Organización:**
      [Detalla la secuencia de actividades en fases: Inicio, Desarrollo y Cierre]

      **Instrumentos de recogida de información:**
      [Lista de instrumentos de evaluación específicos]
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: prompt },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    return response.text || "Error en generación.";
  } catch (error) {
    console.error(error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Download, Edit3, ArrowLeft, Save, FileText, ChevronDown, ChevronUp, Layers, Type, LayoutTemplate } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { CurriculumAnalysis } from '../types';
import CurricularReference from './CurricularReference';

interface EditorProps {
  initialContent: string;
  docTitle: string;
  onRestart: () => void;
  analysisData: CurriculumAnalysis | null;
}

interface DocSection {
  id: number;
  title: string;
  content: string; 
  level: number; 
}

interface SAStructure {
  contextPersonal: string;
  contextEducativo: string;
  contextSocial: string;
  contextProfesional: string;
  justification: string;
  ods: string;
  competencies: string;
  knowledge: string;
  organization: string; 
  instruments: string;
}

const Editor: React.FC<EditorProps> = ({ initialContent, docTitle, onRestart, analysisData }) => {
  const [content, setContent] = useState(initialContent);
  const [mode, setMode] = useState<'edit' | 'preview'>('preview');
  const [sections, setSections] = useState<DocSection[]>([]);
  const [expandedSection, setExpandedSection] = useState<number | null>(null);

  useEffect(() => {
    if (mode === 'edit') {
      const parsed = parseMarkdownToSections(content);
      setSections(parsed);
      if (parsed.length > 0) setExpandedSection(parsed[0].id);
    }
  }, [mode, content]);

  const parseMarkdownToSections = (md: string): DocSection[] => {
    const lines = md.split('\n');
    const result: DocSection[] = [];
    let currentSection: DocSection | null = null;
    let currentBuffer: string[] = [];
    let idCounter = 0;

    const pushCurrent = () => {
      if (currentSection) {
        currentSection.content = currentBuffer.join('\n').trim();
        result.push(currentSection);
      } else if (currentBuffer.length > 0 && currentBuffer.some(l => l.trim() !== '')) {
        result.push({
          id: idCounter++,
          title: "Introducción / Portada",
          content: currentBuffer.join('\n').trim(),
          level: 0
        });
      }
      currentBuffer = [];
    };

    const headerRegex = /^(#{1,6})\s+(.*)$/;

    for (const line of lines) {
      const match = line.match(headerRegex);
      if (match) {
        pushCurrent();
        const level = match[1].length;
        const title = match[2];
        currentSection = {
          id: idCounter++,
          title: title,
          content: "",
          level: level
        };
      } else {
        currentBuffer.push(line);
      }
    }
    pushCurrent();
    return result;
  };

  const handleSectionChange = (id: number, newContent: string) => {
    setSections(prev => prev.map(s => s.id === id ? { ...s, content: newContent } : s));
  };

  const saveSectionsToContent = () => {
    const newContent = sections.map(s => {
      if (s.level === 0) return s.content;
      return `${'#'.repeat(s.level)} ${s.title}\n\n${s.content}`;
    }).join('\n\n');

    setContent(newContent);
    setMode('preview');
  };

  const handleDownload = () => {
    const element = document.createElement("a");
    const file = new Blob([content], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    element.download = `${docTitle.replace(/\s+/g, '_')}_EduPlanner.md`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  return (
    <div className="space-y-4 animate-fade-in">

      <CurricularReference analysisData={analysisData} className="mb-6" />

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm sticky top-20 z-10">
        <div>
          <h2 className="text-lg font-bold text-slate-800">{docTitle}</h2>
          <p className="text-xs text-slate-500">
            {mode === 'preview' ? 'Vista Previa' : 'Modo Edición Estructurada'}
          </p>
        </div>
        <div className="flex items-center gap-2">
          {mode === 'preview' ? (
            <button
              onClick={() => setMode('edit')}
              className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg transition-colors shadow-sm"
            >
              <Edit3 className="w-4 h-4" />
              Editar Secciones
            </button>
          ) : (
            <button
              onClick={saveSectionsToContent}
              className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-emerald-600 hover:bg-emerald-700 rounded-lg transition-colors shadow-sm"
            >
              <Save className="w-4 h-4" />
              Guardar y Ver Vista Previa
            </button>
          )}

          <button
            onClick={handleDownload}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-300 hover:bg-slate-50 rounded-lg transition-colors"
          >
            <Download className="w-4 h-4" />
            Descargar Markdown
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[60vh]">
        {mode === 'edit' ? (
          <div className="p-6 bg-slate-50 space-y-4">
             <div className="bg-blue-50 text-blue-800 text-sm p-3 rounded-lg mb-4 border border-blue-100 flex items-center gap-2">
                <FileText className="w-4 h-4" />
                Edita los campos específicos. Pulsa "Guardar" para ver el resultado final.
             </div>
             {sections.map((section) => (
                <SectionEditor 
                  key={section.id} 
                  section={section} 
                  isExpanded={expandedSection === section.id}
                  onToggle={() => setExpandedSection(expandedSection === section.id ? null : section.id)}
                  onChange={(newContent) => handleSectionChange(section.id, newContent)}
                  onTitleChange={(newTitle) => setSections(prev => prev.map(s => s.id === section.id ? { ...s, title: newTitle } : s))}
                />
             ))}
          </div>
        ) : (
          <div className="markdown-body prose prose-slate max-w-none p-8 h-[60vh] overflow-y-auto custom-scrollbar">
            <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
          </div>
        )}
      </div>

      <div className="flex justify-start">
        <button
          onClick={onRestart}
          className="flex items-center gap-2 text-slate-500 hover:text-slate-800 transition-colors px-2 py-1"
        >
          <ArrowLeft className="w-4 h-4" />
          Crear otro documento
        </button>
      </div>
    </div>
  );
};

interface SectionEditorProps {
  section: DocSection;
  isExpanded: boolean;
  onToggle: () => void;
  onChange: (content: string) => void;
  onTitleChange: (title: string) => void;
}

const SectionEditor: React.FC<SectionEditorProps> = ({ section, isExpanded, onToggle, onChange, onTitleChange }) => {
  const isSA = section.title.toUpperCase().includes("SITUACIÓN DE APRENDIZAJE");
  const [useRaw, setUseRaw] = useState(!isSA);
  const [saData, setSaData] = useState<SAStructure | null>(null);

  useEffect(() => {
    if (isSA && !useRaw && isExpanded) {
      const parsed = parseSAMarkdown(section.content);
      setSaData(parsed);
    }
  }, [isExpanded, isSA, useRaw, section.content]);

  const parseSAMarkdown = (md: string): SAStructure => {
    const extract = (markerStart: string, markerEnd: string | null) => {
      const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      // Búsqueda más flexible permitiendo variaciones en dos puntos o negritas
      const startRegex = new RegExp(`${escapeRegExp(markerStart)}[:\\s]*`, 'i');
      const split = md.split(startRegex);
      if (split.length < 2) return "";

      let rest = split[1];
      if (markerEnd) {
        const endRegex = new RegExp(`[:\\s]*${escapeRegExp(markerEnd)}`, 'i');
        const endSplit = rest.split(endRegex);
        return endSplit[0].trim();
      }
      return rest.trim();
    };

    const contextTable = extract("**Contexto:**", "**Descripción");
    // Procesar la tabla de forma más robusta
    const contextParts = contextTable.split('|')
      .map(s => s.trim())
      .filter(s => s && !s.includes('---') && !/personal|educativo|social|profesional/i.test(s));

    // Si la tabla no se parseó bien, intentamos buscar las celdas directamente
    const contextPersonal = contextParts[0] || "";
    const contextEducativo = contextParts[1] || "";
    const contextSocial = contextParts[2] || "";
    const contextProfesional = contextParts[3] || "";

    return {
      contextPersonal,
      contextEducativo,
      contextSocial,
      contextProfesional,
      justification: extract("**Descripción / Justificación:**", "**Relación con"),
      ods: extract("**Relación con los retos del s.XXI y los ODS:**", "**Competencias Específicas"),
      competencies: extract("**Competencias Específicas y Criterios de Evaluación vinculados:**", "**Saberes Básicos:**"),
      knowledge: extract("**Saberes Básicos:**", "**Organización:**"),
      organization: extract("**Organización:**", "**Instrumentos de recogida"),
      instruments: extract("**Instrumentos de recogida de información:**", null)
    };
  };

  const handleSAChange = (field: keyof SAStructure, value: string) => {
    if (!saData) return;
    const newData = { ...saData, [field]: value };
    setSaData(newData);

    const newMd = `**Contexto:**
| Personal | Educativo | Social | Profesional |
| :--- | :--- | :--- | :--- |
| ${newData.contextPersonal} | ${newData.contextEducativo} | ${newData.contextSocial} | ${newData.contextProfesional} |

**Descripción / Justificación:**
${newData.justification}

**Relación con los retos del s.XXI y los ODS:**
${newData.ods}

**Competencias Específicas y Criterios de Evaluación vinculados:**
${newData.competencies}

**Saberes Básicos:**
${newData.knowledge}

**Organización:**
${newData.organization}

**Instrumentos de recogida de información:**
${newData.instruments}`;

    onChange(newMd);
  };

  return (
    <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden mb-4 transition-all">
      <div 
        className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors border-b border-slate-100 cursor-pointer"
        onClick={onToggle}
      >
        <div className="flex items-center gap-3 flex-1">
          <span className="text-xs font-mono text-slate-400 shrink-0">
            {section.level > 0 ? 'H' + section.level : 'Intro'}
          </span>
          {isExpanded ? (
             <input 
               type="text" 
               value={section.title}
               onClick={(e) => e.stopPropagation()}
               onChange={(e) => onTitleChange(e.target.value)}
               className="font-bold text-slate-700 bg-transparent border-b border-dashed border-slate-300 focus:border-indigo-500 outline-none w-full max-w-lg"
             />
          ) : (
             <h3 className="font-bold text-slate-700 truncate">{section.title}</h3>
          )}
        </div>
        <div className="flex items-center gap-2">
           {isSA && isExpanded && (
             <button 
               onClick={(e) => { e.stopPropagation(); setUseRaw(!useRaw); }}
               className="text-xs px-2 py-1 rounded border border-slate-200 text-slate-500 hover:bg-white"
             >
               {useRaw ? "Modo Campos" : "Modo Markdown"}
             </button>
           )}
           {isExpanded ? <ChevronUp className="w-4 h-4 text-slate-400"/> : <ChevronDown className="w-4 h-4 text-slate-400"/>}
        </div>
      </div>

      {isExpanded && (
        <div className="p-4 bg-white">
          {isSA && !useRaw && saData ? (
            <div className="space-y-6">
              <div>
                <label className="flex items-center gap-2 text-sm font-bold text-slate-700 mb-2">
                  <LayoutTemplate className="w-4 h-4 text-indigo-500" />
                  Contexto
                </label>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <span className="text-xs text-slate-500 uppercase font-semibold">Personal</span>
                    <input className="w-full p-2 border border-slate-200 rounded text-sm" value={saData.contextPersonal} onChange={(e) => handleSAChange('contextPersonal', e.target.value)} />
                  </div>
                  <div className="space-y-1">
                    <span className="text-xs text-slate-500 uppercase font-semibold">Educativo</span>
                    <input className="w-full p-2 border border-slate-200 rounded text-sm" value={saData.contextEducativo} onChange={(e) => handleSAChange('contextEducativo', e.target.value)} />
                  </div>
                  <div className="space-y-1">
                    <span className="text-xs text-slate-500 uppercase font-semibold">Social</span>
                    <input className="w-full p-2 border border-slate-200 rounded text-sm" value={saData.contextSocial} onChange={(e) => handleSAChange('contextSocial', e.target.value)} />
                  </div>
                  <div className="space-y-1">
                    <span className="text-xs text-slate-500 uppercase font-semibold">Profesional</span>
                    <input className="w-full p-2 border border-slate-200 rounded text-sm" value={saData.contextProfesional} onChange={(e) => handleSAChange('contextProfesional', e.target.value)} />
                  </div>
                </div>
              </div>

              <div>
                 <label className="flex items-center gap-2 text-sm font-bold text-slate-700 mb-2">
                   <Type className="w-4 h-4 text-indigo-500" />
                   Descripción / Justificación
                 </label>
                 <textarea 
                   className="w-full min-h-[100px] p-3 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-100 outline-none"
                   value={saData.justification}
                   onChange={(e) => handleSAChange('justification', e.target.value)}
                 />
              </div>

              <div>
                 <label className="flex items-center gap-2 text-sm font-bold text-slate-700 mb-2">
                   <Layers className="w-4 h-4 text-emerald-500" />
                   Retos s.XXI y ODS
                 </label>
                 <textarea 
                   className="w-full min-h-[80px] p-3 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-100 outline-none"
                   value={saData.ods}
                   onChange={(e) => handleSAChange('ods', e.target.value)}
                 />
              </div>

              <div>
                 <label className="text-sm font-bold text-slate-700 mb-2 block">Competencias Específicas y Criterios</label>
                 <textarea 
                   className="w-full min-h-[120px] p-3 border border-slate-200 rounded-lg text-sm font-mono bg-slate-50"
                   value={saData.competencies}
                   onChange={(e) => handleSAChange('competencies', e.target.value)}
                 />
              </div>

              <div>
                 <label className="text-sm font-bold text-slate-700 mb-2 block">Saberes Básicos</label>
                 <textarea 
                   className="w-full min-h-[100px] p-3 border border-slate-200 rounded-lg text-sm font-mono bg-slate-50"
                   value={saData.knowledge}
                   onChange={(e) => handleSAChange('knowledge', e.target.value)}
                 />
              </div>

               <div>
                 <label className="text-sm font-bold text-slate-700 mb-2 block">Organización</label>
                 <textarea 
                   className="w-full min-h-[100px] p-3 border border-slate-200 rounded-lg text-sm font-mono bg-slate-50"
                   value={saData.organization}
                   onChange={(e) => handleSAChange('organization', e.target.value)}
                 />
              </div>

               <div>
                 <label className="text-sm font-bold text-slate-700 mb-2 block">Instrumentos de Evaluación</label>
                 <textarea 
                   className="w-full min-h-[80px] p-3 border border-slate-200 rounded-lg text-sm"
                   value={saData.instruments}
                   onChange={(e) => handleSAChange('instruments', e.target.value)}
                 />
              </div>

            </div>
          ) : (
            <textarea
              value={section.content}
              onChange={(e) => onChange(e.target.value)}
              className="w-full min-h-[300px] p-3 border border-slate-300 rounded-md font-mono text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              placeholder="Escribe aquí el contenido de esta sección..."
            />
          )}
        </div>
      )}
    </div>
  );
};

export default Editor;

import { GoogleGenAI } from "@google/genai";
import { DocType, TeacherContext, CurriculumAnalysis } from "../types";

// Función para obtener el cliente de IA con la mejor clave disponible
const getAiClient = () => {
  const manualKey = localStorage.getItem('GEMINI_API_KEY');
  const apiKey = manualKey || process.env.API_KEY;

  if (!apiKey) {
    throw new Error("No se ha configurado ninguna API KEY. Por favor, configúrala en el icono de ajustes.");
  }

  return new GoogleGenAI({ apiKey });
};

const SYSTEM_INSTRUCTION = `
Eres un experto pedagogo y jefe de departamento con amplia experiencia en normativa educativa (LOMLOE) y diseño curricular.
Tu objetivo es redactar documentos oficiales precisos basándote en el currículum oficial (PDF) y el contexto proporcionado.
Debes seguir estrictamente la estructura de Markdown solicitada para que el sistema pueda procesar los campos.
Usa un lenguaje técnico, inclusivo y profesional.
IMPORTANTE: Debes escribir el documento ÚNICA Y EXCLUSIVAMENTE en el idioma solicitado por el usuario.
`;

export const analyzePdfStructure = async (pdfBase64: string): Promise<CurriculumAnalysis> => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: `Analiza este PDF del currículum oficial.
          Extrae la siguiente información estructurada en JSON:
          1. "subject": Nombre probable de la Asignatura.
          2. "grade": Curso/Nivel académico.
          3. "competencies": Una lista (array de strings) de las Competencias Específicas. 
             IMPORTANTE: Cada string DEBE empezar con su código (ej: "CE1: [Título]", "CE2: [Título]"). Si el PDF no tiene códigos, invéntalos correlativamente.
          4. "blocks": Una lista (array de strings) de los Bloques de Saberes Básicos. 
             IMPORTANTE: Cada string DEBE empezar con "Bloque X: [Nombre del bloque]".

          Devuelve SOLO el JSON raw.` }
        ]
      },
      config: { 
        responseMimeType: "application/json" 
      }
    });

    let text = response.text || "{}";
    const parsed = JSON.parse(text);
    return {
      subject: parsed.subject || "",
      grade: parsed.grade || "",
      competencies: parsed.competencies || [],
      blocks: parsed.blocks || []
    };
  } catch (e) {
    console.error("Error analyzing PDF", e);
    return { subject: "", grade: "", competencies: [], blocks: [] };
  }
};

export const generateEducationalDocument = async (
  pdfBase64: string,
  context: TeacherContext,
  docType: DocType
): Promise<string> => {
  const ai = getAiClient();
  let prompt = "";
  const needsString = [...context.selectedNeeds, context.otherNeeds].filter(Boolean).join(", ");
  const methodologiesString = context.methodologyPreference.join(", ");
  const langInstruction = `EL DOCUMENTO DEBE ESTAR ESCRITO ÍNTEGRAMENTE EN: ${context.language}.`;

  if (docType === DocType.PROPUESTA) {
    prompt = `
      ${langInstruction}
      Genera una **PROPUESTA PEDAGÓGICA DE DEPARTAMENTO**.
      Usa exactamente estos encabezados de nivel 2:

      # PROPUESTA PEDAGÓGICA: ${context.subject}
      ## 1. Concreción Curricular
      Detalla competencias específicas y criterios del PDF vinculados a ${context.gradeLevel}.
      ## 2. Metodología y Estrategias
      Basadas en: ${methodologiesString}.
      ## 3. Evaluación
      Instrumentos, criterios de calificación y temporalización (basado en ${context.weeklyHours}h/semana).
      ## 4. Atención a la Diversidad
      Medidas específicas para: ${needsString}.
    `;
  } else {
    prompt = `
      ${langInstruction}
      Genera ${context.numberOfSAs} **SITUACIONES DE APRENDIZAJE** detalladas para ${context.subject} (${context.gradeLevel}).

      PARA CADA SITUACIÓN DE APRENDIZAJE, debes usar EXACTAMENTE esta estructura y etiquetas:

      ## SITUACIÓN DE APRENDIZAJE: [Título Sugerente]

      **Contexto:**
      | Personal | Educativo | Social | Profesional |
      | :--- | :--- | :--- | :--- |
      | [Descripción corta] | [Descripción corta] | [Descripción corta] | [Descripción corta] |

      **Descripción / Justificación:**
      [Escribe aquí la justificación pedagógica y el reto o producto final esperado]

      **Relación con los retos del s.XXI y los ODS:**
      [Escribe aquí la vinculación con ODS]

      **Competencias Específicas y Criterios de Evaluación vinculados:**
      [Cita las competencias específicas del PDF que se trabajan]

      **Saberes Básicos:**
      [Lista los saberes del PDF involucrados]

      **Organización:**
      [Detalla la secuencia de actividades en fases: Inicio, Desarrollo y Cierre]

      **Instrumentos de recogida de información:**
      [Lista de instrumentos de evaluación específicos]
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: prompt },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    return response.text || "Error en generación.";
  } catch (error) {
    console.error(error);
    throw error;
  }
};

import React, { useState } from 'react';
import { BookOpen, ChevronDown, ChevronUp, Layers, Bookmark } from 'lucide-react';
import { CurriculumAnalysis } from '../types';

interface CurricularReferenceProps {
  analysisData: CurriculumAnalysis | null;
  className?: string;
}

const CurricularReference: React.FC<CurricularReferenceProps> = ({ analysisData, className = "" }) => {
  const [showAnalysis, setShowAnalysis] = useState(false);

  if (!analysisData) return null;

  const renderItemWithCode = (text: string, type: 'ce' | 'block') => {
    // Intentamos separar el código (ej: CE1, Bloque 1) del contenido
    const parts = text.split(/[:\s-]{1,2}/);
    if (parts.length > 1 && (parts[0].toUpperCase().startsWith('CE') || parts[0].toUpperCase().startsWith('BLOQUE'))) {
      const code = parts[0];
      const content = text.substring(code.length).replace(/^[:\s-]{1,2}/, '').trim();

      return (
        <li className="text-xs text-slate-600 flex items-start gap-2 group">
          <span className={`flex-shrink-0 px-1.5 py-0.5 rounded text-[10px] font-bold uppercase tracking-tight
            ${type === 'ce' ? 'bg-emerald-100 text-emerald-700 border border-emerald-200' : 'bg-blue-100 text-blue-700 border border-blue-200'}`}>
            {code}
          </span>
          <span className="mt-0.5 leading-relaxed">{content}</span>
        </li>
      );
    }

    // Fallback si no hay código detectable
    return (
      <li className="text-xs text-slate-600 flex items-start gap-2">
        <span className={`${type === 'ce' ? 'text-emerald-500' : 'text-blue-500'} mt-1`}>•</span>
        {text}
      </li>
    );
  };

  return (
    <div className={`bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden ${className}`}>
      <button 
        type="button"
        onClick={() => setShowAnalysis(!showAnalysis)}
        className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 transition-colors"
      >
        <div className="flex items-center gap-2">
          <BookOpen className="w-5 h-5 text-indigo-600" />
          <span className="font-semibold text-slate-700">Referencia Curricular Extraída</span>
          <span className="text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full">
            {analysisData.subject || "Sin asignatura"}
          </span>
        </div>
        {showAnalysis ? <ChevronUp className="w-5 h-5 text-slate-400" /> : <ChevronDown className="w-5 h-5 text-slate-400" />}
      </button>

      {showAnalysis && (
        <div className="p-6 border-t border-slate-100 grid grid-cols-1 md:grid-cols-2 gap-8 bg-white max-h-[400px] overflow-y-auto custom-scrollbar">
          <div>
            <h4 className="flex items-center gap-2 font-bold text-slate-800 mb-3 text-sm sticky top-0 bg-white py-1">
              <Layers className="w-4 h-4 text-emerald-500" />
              Competencias Específicas
            </h4>
            <ul className="space-y-3">
              {analysisData.competencies && analysisData.competencies.length > 0 ? (
                analysisData.competencies.map((comp, idx) => (
                  <React.Fragment key={idx}>
                    {renderItemWithCode(comp, 'ce')}
                  </React.Fragment>
                ))
              ) : (
                <li className="text-xs text-slate-400 italic">No se detectaron competencias específicas.</li>
              )}
            </ul>
          </div>

          <div>
            <h4 className="flex items-center gap-2 font-bold text-slate-800 mb-3 text-sm sticky top-0 bg-white py-1">
              <Bookmark className="w-4 h-4 text-blue-500" />
              Bloques de Saberes
            </h4>
             <ul className="space-y-3">
              {analysisData.blocks && analysisData.blocks.length > 0 ? (
                analysisData.blocks.map((block, idx) => (
                  <React.Fragment key={idx}>
                    {renderItemWithCode(block, 'block')}
                  </React.Fragment>
                ))
              ) : (
                <li className="text-xs text-slate-400 italic">No se detectaron bloques de saberes.</li>
              )}
            </ul>
          </div>
        </div>
      )}
    </div>
  );
};

