import { GoogleGenAI } from "@google/genai";
import { DocType, TeacherContext, CurriculumAnalysis } from "../types";

const getAiClient = () => {
  const manualKey = localStorage.getItem('GEMINI_API_KEY');
  const apiKey = manualKey || process.env.API_KEY;

  if (!apiKey) {
    throw new Error("No se ha configurado ninguna API KEY. Por favor, configúrala en el icono de ajustes.");
  }

  return new GoogleGenAI({ apiKey });
};

const SYSTEM_INSTRUCTION = `
Eres un experto pedagogo y jefe de departamento con amplia experiencia en normativa educativa (LOMLOE) y diseño curricular.
Tu objetivo es redactar documentos oficiales precisos basándote en el currículum oficial (PDF) y el contexto proporcionado.
Debes seguir estrictamente la estructura de Markdown solicitada para que el sistema pueda procesar los campos.
Usa un lenguaje técnico, inclusivo y profesional.
IMPORTANTE: Debes escribir el documento ÚNICA Y EXCLUSIVAMENTE en el idioma solicitado por el usuario.
`;

export const analyzePdfStructure = async (pdfBase64: string): Promise<CurriculumAnalysis> => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: `Analiza este PDF del currículum oficial.
          Extrae la siguiente información estructurada en JSON:
          1. "subject": Nombre probable de la Asignatura.
          2. "grade": Curso/Nivel académico.
          3. "competencies": Una lista (array de strings) de las Competencias Específicas. 
             IMPORTANTE: Cada string DEBE empezar con su código (ej: "CE1: [Título]").
          4. "blocks": Una lista (array de strings) de los Bloques de Saberes Básicos. 
             IMPORTANTE: Cada string DEBE empezar con "Bloque X: [Nombre]".

          Devuelve SOLO el JSON raw.` }
        ]
      },
      config: { 
        responseMimeType: "application/json" 
      }
    });

    let text = response.text || "{}";
    const parsed = JSON.parse(text);
    return {
      subject: parsed.subject || "",
      grade: parsed.grade || "",
      competencies: parsed.competencies || [],
      blocks: parsed.blocks || []
    };
  } catch (e) {
    console.error("Error analyzing PDF", e);
    return { subject: "", grade: "", competencies: [], blocks: [] };
  }
};

export const generateEducationalDocument = async (
  pdfBase64: string,
  context: TeacherContext,
  docType: DocType
): Promise<string> => {
  const ai = getAiClient();
  let prompt = "";
  const needsString = [...context.selectedNeeds, context.otherNeeds].filter(Boolean).join(", ");
  const methodologiesString = context.methodologyPreference.join(", ");
  const langInstruction = `EL DOCUMENTO DEBE ESTAR ESCRITO ÍNTEGRAMENTE EN: ${context.language}.`;

  if (docType === DocType.PROPUESTA) {
    prompt = `
      ${langInstruction}
      Genera una **PROPUESTA PEDAGÓGICA DE DEPARTAMENTO**.
      Usa exactamente estos encabezados de nivel 2:

      # PROPUESTA PEDAGÓGICA: ${context.subject}
      ## 1. Concreción Curricular
      Detalla competencias específicas y criterios del PDF vinculados a ${context.gradeLevel}.
      ## 2. Metodología y Estrategias
      Basadas en: ${methodologiesString}.
      ## 3. Evaluación
      Instrumentos, criterios de calificación y temporalización (basado en ${context.weeklyHours}h/semana).
      ## 4. Atención a la Diversidad
      Medidas específicas para: ${needsString}.
    `;
  } else {
    prompt = `
      ${langInstruction}
      Genera ${context.numberOfSAs} **SITUACIONES DE APRENDIZAJE** detalladas para ${context.subject} (${context.gradeLevel}).

      PARA CADA SITUACIÓN DE APRENDIZAJE, debes usar EXACTAMENTE esta estructura:

      ## SITUACIÓN DE APRENDIZAJE: [Título Sugerente]

      **Contexto:**
      | Personal | Educativo | Social | Profesional |
      | :--- | :--- | :--- | :--- |
      | [Descripción] | [Descripción] | [Descripción] | [Descripción] |

      **Descripción / Justificación:**
      [Justificación pedagógica]

      **Relación con los retos del s.XXI y los ODS:**
      [Vinculación con ODS]

      **Competencias Específicas y Criterios de Evaluación vinculados:**
      [Cita competencias del PDF]

      **Saberes Básicos:**
      [Saberes del PDF]

      **Organización:**
      Genera una tabla con al menos 3 filas (Actividad 1, Actividad 2, Actividad 3).
      | Sequenciació d'activitats | Organització dels espais | Distribució del temps | Recursos i materials | Mesures de resposta educativa per a la inclusió |
      | :--- | :--- | :--- | :--- | :--- |
      | **Actividad 1:** [Nombre] | [Espacio] | [Tiempo] | [Recursos] | [Medidas] |
      | **Actividad 2:** [Nombre] | [Espacio] | [Tiempo] | [Recursos] | [Medidas] |
      | **Actividad 3:** [Nombre] | [Espacio] | [Tiempo] | [Recursos] | [Medidas] |

      **Instrumentos de recogida de información:**
      [Lista de instrumentos]
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: prompt },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    return response.text || "Error en generación.";
  } catch (error) {
    console.error(error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Download, Edit3, ArrowLeft, Save, FileText, ChevronDown, ChevronUp, Layers, Type, LayoutTemplate, FileJson, FileType, Printer, Plus, Trash2 } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { CurriculumAnalysis } from '../types';
import CurricularReference from './CurricularReference';

interface EditorProps {
  initialContent: string;
  docTitle: string;
  onRestart: () => void;
  analysisData: CurriculumAnalysis | null;
}

interface DocSection {
  id: number;
  title: string;
  content: string; 
  level: number; 
}

interface ActivityRow {
  sequencing: string;
  spaces: string;
  time: string;
  resources: string;
  inclusion: string;
}

interface SAStructure {
  contextPersonal: string;
  contextEducativo: string;
  contextSocial: string;
  contextProfesional: string;
  justification: string;
  ods: string;
  competencies: string;
  knowledge: string;
  activities: ActivityRow[];
  instruments: string;
}

const Editor: React.FC<EditorProps> = ({ initialContent, docTitle, onRestart, analysisData }) => {
  const [content, setContent] = useState(initialContent);
  const [mode, setMode] = useState<'edit' | 'preview'>('preview');
  const [sections, setSections] = useState<DocSection[]>([]);
  const [expandedSection, setExpandedSection] = useState<number | null>(null);
  const previewRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (mode === 'edit') {
      const parsed = parseMarkdownToSections(content);
      setSections(parsed);
      if (parsed.length > 0) setExpandedSection(parsed[0].id);
    }
  }, [mode, content]);

  const parseMarkdownToSections = (md: string): DocSection[] => {
    const lines = md.split('\n');
    const result: DocSection[] = [];
    let currentSection: DocSection | null = null;
    let currentBuffer: string[] = [];
    let idCounter = 0;

    const pushCurrent = () => {
      if (currentSection) {
        currentSection.content = currentBuffer.join('\n').trim();
        result.push(currentSection);
      } else if (currentBuffer.length > 0 && currentBuffer.some(l => l.trim() !== '')) {
        result.push({
          id: idCounter++,
          title: "Portada / Introducción",
          content: currentBuffer.join('\n').trim(),
          level: 0
        });
      }
      currentBuffer = [];
    };

    const headerRegex = /^(#{1,6})\s+(.*)$/;

    for (const line of lines) {
      const match = line.match(headerRegex);
      if (match) {
        pushCurrent();
        const level = match[1].length;
        const title = match[2];
        currentSection = {
          id: idCounter++,
          title: title,
          content: "",
          level: level
        };
      } else {
        currentBuffer.push(line);
      }
    }
    pushCurrent();
    return result;
  };

  const handleSectionChange = (id: number, newContent: string) => {
    setSections(prev => prev.map(s => s.id === id ? { ...s, content: newContent } : s));
  };

  const saveSectionsToContent = () => {
    const newContent = sections.map(s => {
      if (s.level === 0) return s.content;
      return `${'#'.repeat(s.level)} ${s.title}\n\n${s.content}`;
    }).join('\n\n');

    setContent(newContent);
    setMode('preview');
  };

  const downloadFile = (data: Blob, filename: string) => {
    const element = document.createElement("a");
    element.href = URL.createObjectURL(data);
    element.download = filename;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const handleDownloadMD = () => {
    const blob = new Blob([content], {type: 'text/markdown'});
    downloadFile(blob, `${docTitle.replace(/\s+/g, '_')}.md`);
  };

  const handleDownloadODT = () => {
    const htmlString = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>${docTitle}</title>
      <style>
        body { font-family: 'Arial', sans-serif; line-height: 1.5; color: #333; }
        table { border-collapse: collapse; width: 100%; margin: 20px 0; }
        th, td { border: 1px solid #999; padding: 10px; text-align: left; font-size: 10pt; }
        th { background-color: #f3f4f6; font-weight: bold; }
        h1 { font-size: 24pt; color: #1a365d; margin-bottom: 20pt; }
        h2 { font-size: 18pt; color: #2c5282; border-bottom: 2px solid #e2e8f0; padding-bottom: 5pt; margin-top: 30pt; }
        h3 { font-size: 14pt; color: #4a5568; margin-top: 20pt; }
        p { margin-bottom: 10pt; }
      </style>
      </head>
      <body>
        ${previewRef.current?.innerHTML || ''}
      </body>
      </html>
    `;
    const blob = new Blob([htmlString], {type: 'application/vnd.oasis.opendocument.text'});
    downloadFile(blob, `${docTitle.replace(/\s+/g, '_')}.odt`);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  return (
    <div className="space-y-4 animate-fade-in">
      <div className="print:hidden">
        <CurricularReference analysisData={analysisData} className="mb-6" />
      </div>

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm sticky top-20 z-10 print:hidden">
        <div>
          <h2 className="text-lg font-bold text-slate-800">{docTitle}</h2>
          <p className="text-xs text-slate-500">
            {mode === 'preview' ? 'Vista Previa' : 'Edición por Campos'}
          </p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          {mode === 'preview' ? (
            <button
              onClick={() => setMode('edit')}
              className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg transition-colors shadow-sm"
            >
              <Edit3 className="w-4 h-4" />
              Modo Edición
            </button>
          ) : (
            <button
              onClick={saveSectionsToContent}
              className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-white bg-emerald-600 hover:bg-emerald-700 rounded-lg transition-colors shadow-sm"
            >
              <Save className="w-4 h-4" />
              Guardar Cambios
            </button>
          )}

          <div className="h-6 w-[1px] bg-slate-200 mx-1 hidden sm:block"></div>

          <button
            onClick={handleDownloadMD}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold text-slate-600 bg-slate-50 border border-slate-200 hover:bg-slate-100 rounded-lg transition-colors"
          >
            <FileJson className="w-3.5 h-3.5" /> .MD
          </button>

          <button
            onClick={handleDownloadODT}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold text-blue-600 bg-blue-50 border border-blue-100 hover:bg-blue-100 rounded-lg transition-colors"
          >
            <FileType className="w-3.5 h-3.5" /> .ODT
          </button>

          <button
            onClick={handlePrintPDF}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold text-rose-600 bg-rose-50 border border-rose-100 hover:bg-rose-100 rounded-lg transition-colors"
          >
            <Printer className="w-3.5 h-3.5" /> PDF
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[60vh] print:border-none print:shadow-none">
        {mode === 'edit' ? (
          <div className="p-6 bg-slate-50 space-y-4">
             {sections.map((section) => (
                <SectionEditor 
                  key={section.id} 
                  section={section} 
                  isExpanded={expandedSection === section.id}
                  onToggle={() => setExpandedSection(expandedSection === section.id ? null : section.id)}
                  onChange={(newContent) => handleSectionChange(section.id, newContent)}
                  onTitleChange={(newTitle) => setSections(prev => prev.map(s => s.id === section.id ? { ...s, title: newTitle } : s))}
                />
             ))}
          </div>
        ) : (
          <div className="markdown-body prose prose-slate max-w-none p-8 min-h-[60vh] overflow-y-auto custom-scrollbar print:p-0 print:overflow-visible" ref={previewRef}>
            <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
          </div>
        )}
      </div>

      <div className="flex justify-start print:hidden">
        <button onClick={onRestart} className="flex items-center gap-2 text-slate-500 hover:text-slate-800 transition-colors px-2 py-1">
          <ArrowLeft className="w-4 h-4" /> Crear otro documento
        </button>
      </div>
    </div>
  );
};

interface SectionEditorProps {
  section: DocSection;
  isExpanded: boolean;
  onToggle: () => void;
  onChange: (content: string) => void;
  onTitleChange: (title: string) => void;
}

const SectionEditor: React.FC<SectionEditorProps> = ({ section, isExpanded, onToggle, onChange, onTitleChange }) => {
  const isSA = section.title.toUpperCase().includes("SITUACIÓN DE APRENDIZAJE");
  const [useRaw, setUseRaw] = useState(!isSA);
  const [saData, setSaData] = useState<SAStructure | null>(null);

  useEffect(() => {
    if (isSA && !useRaw && isExpanded) {
      setSaData(parseSAMarkdown(section.content));
    }
  }, [isExpanded, isSA, useRaw, section.content]);

  const parseSAMarkdown = (md: string): SAStructure => {
    const extract = (markerStart: string, markerEnd: string | null) => {
      const escapeRegExp = (s: string) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const startPattern = `(?:\\*\\*${escapeRegExp(markerStart.replace(/\*\*/g, ''))}\\*\\*|${escapeRegExp(markerStart.replace(/\*\*/g, ''))})[:\\s]*`;
      const split = md.split(new RegExp(startPattern, 'i'));
      if (split.length < 2) return "";
      let rest = split[1];
      if (markerEnd) {
        const endPattern = `(?:\\*\\*${escapeRegExp(markerEnd.replace(/\*\*/g, ''))}\\*\\*|${escapeRegExp(markerEnd.replace(/\*\*/g, ''))})[:\\s]*`;
        return rest.split(new RegExp(endPattern, 'i'))[0].trim();
      }
      return rest.trim();
    };

    // Contexto
    const ctxTable = extract("Contexto:", "Descripción");
    const ctxRows = ctxTable.split('\n').filter(l => l.includes('|') && !l.includes('---'));
    const ctxParts = ctxRows.length > 1 ? ctxRows[1].split('|').map(s => s.trim()).filter(s => s !== "") : [];

    // Organización (Actividades)
    const orgTable = extract("Organización:", "Instrumentos");
    const orgRows = orgTable.split('\n').filter(l => l.includes('|') && !l.includes('---') && !/sequenciaci|activitats/i.test(l));
    const activities: ActivityRow[] = orgRows.map(row => {
      const cols = row.split('|').map(s => s.trim()).filter(s => s !== "");
      return {
        sequencing: cols[0] || "",
        spaces: cols[1] || "",
        time: cols[2] || "",
        resources: cols[3] || "",
        inclusion: cols[4] || ""
      };
    });

    return {
      contextPersonal: ctxParts[0] || "",
      contextEducativo: ctxParts[1] || "",
      contextSocial: ctxParts[2] || "",
      contextProfesional: ctxParts[3] || "",
      justification: extract("Descripción / Justificación:", "Relación con"),
      ods: extract("Relación con los retos del s.XXI y los ODS:", "Competencias Específicas"),
      competencies: extract("Competencias Específicas y Criterios de Evaluación vinculados:", "Saberes Básicos:"),
      knowledge: extract("Saberes Básicos:", "Organización:"),
      activities: activities.length > 0 ? activities : [{ sequencing: "", spaces: "", time: "", resources: "", inclusion: "" }],
      instruments: extract("Instrumentos de recogida de información:", null)
    };
  };

  const syncToMd = (newData: SAStructure) => {
    const tableRows = newData.activities.map(a => 
      `| ${a.sequencing} | ${a.spaces} | ${a.time} | ${a.resources} | ${a.inclusion} |`
    ).join('\n');

    const newMd = `**Contexto:**
| Personal | Educativo | Social | Profesional |
| :--- | :--- | :--- | :--- |
| ${newData.contextPersonal} | ${newData.contextEducativo} | ${newData.contextSocial} | ${newData.contextProfesional} |

**Descripción / Justificación:**
${newData.justification}

**Relación con los retos del s.XXI y los ODS:**
${newData.ods}

**Competencias Específicas y Criterios de Evaluación vinculados:**
${newData.competencies}

**Saberes Básicos:**
${newData.knowledge}

**Organización:**
| Sequenciació d'activitats | Organització dels espais | Distribució del temps | Recursos i materials | Mesures de resposta educativa per a la inclusió |
| :--- | :--- | :--- | :--- | :--- |
${tableRows}

**Instrumentos de recogida de información:**
${newData.instruments}`;

    onChange(newMd);
  };

  const handleSAChange = (field: keyof SAStructure, value: any) => {
    if (!saData) return;
    const updated = { ...saData, [field]: value };
    setSaData(updated);
    syncToMd(updated);
  };

  const updateActivity = (index: number, field: keyof ActivityRow, value: string) => {
    if (!saData) return;
    const newActs = [...saData.activities];
    newActs[index] = { ...newActs[index], [field]: value };
    handleSAChange('activities', newActs);
  };

  return (
    <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden mb-4">
      <div className="flex items-center justify-between p-4 bg-slate-50 border-b border-slate-100 cursor-pointer" onClick={onToggle}>
        <div className="flex items-center gap-3 flex-1">
