  initialData: TeacherContext;
  analysisData: CurriculumAnalysis | null;
  onReAnalyze: () => void;
  onSubmit: (data: TeacherContext) => void;
}

const COMMON_NEEDS = [
  "Alumnado TDAH",
  "Altas Capacidades",
  "Dislexia / DEA",
  "Medidas Nivel II (Apoyo ordinario)",
  "Medidas Nivel III (Apoyo específico)",
  "Desconocimiento del idioma",
  "Problemas de conducta",
  "Discapacidad motora"
];

const METHODOLOGIES = [
  "Aprendizaje Basado en Proyectos (ABP)",
  "Flipped Classroom",
  "Gamificación",
  "Aprendizaje Cooperativo",
  "Instrucción Directa y Práctica",
  "Aprendizaje Basado en Retos",
  "Aprendizaje Servicio (ApS)",
  "Design Thinking"
];

const GRADE_LEVELS = [
  "1ºESO",
  "2ºESO",
  "3ºESO",
  "4ºESO",
  "1º Bachiller",
  "2º Bachiller"
];

const ContextForm: React.FC<ContextFormProps> = ({ initialData, analysisData, onReAnalyze, onSubmit }) => {
  const [formData, setFormData] = useState<TeacherContext>(initialData);

  const isAnalysisIncomplete = !analysisData || 
    !analysisData.subject || 
    !analysisData.grade || 
    analysisData.competencies.length === 0 || 
    analysisData.blocks.length === 0;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'numberOfSAs') {
      const num = parseInt(value) || 1;
      const clampedNum = Math.min(Math.max(num, 1), 15);

      setFormData(prev => {
        const newIdeas = [...prev.saIdeas];
        if (newIdeas.length < clampedNum) {
          while (newIdeas.length < clampedNum) newIdeas.push('');
        } else {
          newIdeas.length = clampedNum;
        }
        return { ...prev, numberOfSAs: clampedNum, saIdeas: newIdeas };
      });
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleIdeaChange = (index: number, value: string) => {
    setFormData(prev => {
      const newIdeas = [...prev.saIdeas];
      newIdeas[index] = value;
      return { ...prev, saIdeas: newIdeas };
    });
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    if (name === 'generateFullCourse') {
      setFormData(prev => ({ ...prev, generateFullCourse: checked }));
    }
  };

  const handleNeedToggle = (need: string) => {
    setFormData(prev => {
      const currentNeeds = prev.selectedNeeds || [];
      if (currentNeeds.includes(need)) {
        return { ...prev, selectedNeeds: currentNeeds.filter(n => n !== need) };
      } else {
        return { ...prev, selectedNeeds: [...currentNeeds, need] };
      }
    });
  };

  const handleMethodologyToggle = (method: string) => {
    setFormData(prev => {
      const currentMethods = prev.methodologyPreference || [];
      if (currentMethods.includes(method)) {
        return { ...prev, methodologyPreference: currentMethods.filter(m => m !== method) };
      } else {
        return { ...prev, methodologyPreference: [...currentMethods, method] };
      }
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.gradeLevel) {
      alert("Por favor, selecciona un curso.");
      return;
    }
    onSubmit(formData);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {isAnalysisIncomplete && (
        <div className="bg-red-50 border border-red-200 p-4 rounded-xl flex items-start gap-4 text-red-800">
          <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <div className="flex-1">
            <p className="font-semibold text-sm">Detección automática incompleta</p>
            <p className="text-xs mt-1">La IA no ha podido extraer todos los datos curriculares del PDF. Puedes rellenarlos manualmente abajo o intentar analizar el archivo de nuevo.</p>
            <button 
              type="button"
              onClick={onReAnalyze}
              className="mt-3 flex items-center gap-2 text-xs font-bold bg-white hover:bg-red-50 px-3 py-1.5 rounded-lg transition-colors border border-red-200"
            >
              <RefreshCw className="w-3 h-3" />
              Reintentar análisis del PDF
            </button>
          </div>
        </div>
      )}

      <CurricularReference analysisData={analysisData} />

      <form onSubmit={handleSubmit} className="bg-white p-8 rounded-xl shadow-sm border border-slate-200 space-y-8">
        <div className="border-b border-slate-100 pb-4">
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <BookOpen className="w-6 h-6 text-indigo-600" />
            Datos Generales
          </h2>
          <p className="text-slate-500 mt-1">Revisa la asignatura y selecciona el curso específico.</p>
        </div>

        {/* Row 1: Subject & Department */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700">Asignatura / Materia</label>
            <input
              type="text"
              name="subject"
              required
              value={formData.subject}
              onChange={handleChange}
              placeholder="Ej: Biología y Geología"
              className="w-full px-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700">Departamento Didáctico</label>
            <input
              type="text"
              name="department"
              required
              value={formData.department}
              onChange={handleChange}
              placeholder="Ej: Departamento de Ciencias"
              className="w-full px-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
          </div>
        </div>

        {/* Row 2: Level, Hours & Language */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
              <GraduationCap className="w-4 h-4 text-slate-400" />
              Curso / Nivel <span className="text-rose-500">*</span>
            </label>
            <select
              name="gradeLevel"
              required
              value={formData.gradeLevel}
              onChange={handleChange}
              className={`w-full px-4 py-2.5 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all bg-white font-medium ${!formData.gradeLevel ? 'border-rose-200 text-slate-400' : 'border-slate-300 text-slate-700'}`}
            >
              <option value="" disabled>Selecciona un curso...</option>
              {GRADE_LEVELS.map(level => (
                <option key={level} value={level}>{level}</option>
              ))}
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
              <Clock className="w-4 h-4 text-slate-400" />
              Horas Semanales
            </label>
            <input
              type="number"
              name="weeklyHours"
              required
              min="1"
              max="30"
              value={formData.weeklyHours || ''}
              onChange={handleChange}
              placeholder="Ej: 3"
              className="w-full px-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
              <Globe className="w-4 h-4 text-slate-400" />
              Idioma Documento
            </label>
            <select
              name="language"
              value={formData.language}
              onChange={handleChange}
              className="w-full px-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all bg-white"
            >
              <option value="Castellano">Castellano</option>
              <option value="Catalán / Valenciano">Catalán / Valenciano</option>
              <option value="Inglés">Inglés</option>
            </select>
          </div>
        </div>

        <hr className="border-slate-100" />

        {/* Section: Methodologies */}
        <div>
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Briefcase className="w-5 h-5 text-indigo-600" />
            Metodologías Activas
          </h3>
          <p className="text-sm text-slate-500 mb-4">Selecciona las metodologías que se aplicarán en el aula:</p>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 mb-4">
            {METHODOLOGIES.map((method) => (
              <button
                key={method}
                type="button"
                onClick={() => handleMethodologyToggle(method)}
                className={`flex items-center gap-2 px-3 py-2.5 rounded-xl border text-sm text-left transition-all ${
                  formData.methodologyPreference.includes(method)
                    ? 'bg-indigo-50 border-indigo-500 text-indigo-700 ring-1 ring-indigo-500 shadow-sm'
                    : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300 hover:bg-slate-50'
                }`}
              >
                 {formData.methodologyPreference.includes(method) ? (
                  <CheckSquare className="w-4 h-4 shrink-0" />
                ) : (
                  <Square className="w-4 h-4 shrink-0" />
                )}
                <span>{method}</span>
              </button>
            ))}
          </div>
        </div>

        <hr className="border-slate-100" />

        {/* Section: Needs */}
        <div>
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Users className="w-5 h-5 text-indigo-600" />
            Atención a la Diversidad (Inclusión)
          </h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
            {COMMON_NEEDS.map((need) => (
              <button
                key={need}
                type="button"
                onClick={() => handleNeedToggle(need)}
                className={`flex items-center gap-2 px-3 py-2.5 rounded-xl border text-sm text-left transition-all ${
                  formData.selectedNeeds.includes(need)
                    ? 'bg-indigo-50 border-indigo-500 text-indigo-700 ring-1 ring-indigo-500 shadow-sm'
                    : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300 hover:bg-slate-50'
                }`}
              >
                {formData.selectedNeeds.includes(need) ? (
                  <CheckSquare className="w-4 h-4 shrink-0" />
                ) : (
                  <Square className="w-4 h-4 shrink-0" />
                )}
                <span>{need}</span>
              </button>
            ))}
          </div>
          <textarea
            name="otherNeeds"
            value={formData.otherNeeds}
            onChange={handleChange}
            rows={2}
            placeholder="Otras necesidades específicas o notas sobre el grupo..."
            className="w-full px-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
          />
        </div>

        <hr className="border-slate-100" />

        {/* Section: Settings */}
        <div className="space-y-4">
           <label className="text-sm font-semibold text-slate-700 block">Planificación de Situaciones de Aprendizaje</label>

           <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-4 shadow-inner">
              <label className="flex items-center gap-3 cursor-pointer group">
                <input 
                  type="checkbox"
                  name="generateFullCourse"
                  checked={formData.generateFullCourse}
                  onChange={handleCheckboxChange}
                  className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300 transition-all"
                />
                <span className="text-slate-800 font-bold group-hover:text-indigo-600 transition-colors">Generar SAs para todo el curso</span>
              </label>

              <div className={`transition-all duration-300 space-y-6 ${formData.generateFullCourse ? 'opacity-40 pointer-events-none' : 'opacity-100'}`}>
                <div>
                  <label className="text-sm font-medium text-slate-600 mb-1.5 block">¿Cuántas SAs quieres generar ahora?</label>
                  <div className="flex items-center gap-3">
                    <input
                      type="number"
                      name="numberOfSAs"
                      min="1"
                      max="15"
                      value={formData.numberOfSAs}
                      onChange={handleChange}
                      className="w-full max-w-[120px] px-3 py-2 border border-slate-300 rounded-lg shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    />
                    <span className="text-xs text-slate-400 italic font-medium">Máximo 15 por generación</span>
                  </div>
                </div>

                {/* Ideas dinámicas para cada SA */}
                <div className="space-y-4 animate-fade-in-down">
                  <div className="flex items-center gap-2 text-indigo-800 font-bold text-sm">
                    <Lightbulb className="w-4 h-4" />
                    Propuestas para cada situación (Opcional)
                  </div>
                  <div className="grid grid-cols-1 gap-4">
                    {Array.from({ length: formData.numberOfSAs }).map((_, idx) => (
                      <div key={idx} className="space-y-1.5">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                          Idea para Situación {idx + 1}
                        </label>
                        <textarea
                          value={formData.saIdeas[idx] || ''}
                          onChange={(e) => handleIdeaChange(idx, e.target.value)}
                          placeholder="Ej: Tratar la sostenibilidad mediante un huerto escolar..."
                          className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-400 outline-none text-sm bg-white"
                          rows={2}
                        />
                      </div>
                    ))}
                  </div>
                </div>
              </div>
           </div>
        </div>

        <div className="pt-4 flex justify-end">
          <button
            type="submit"
            className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-8 rounded-xl shadow-lg hover:shadow-indigo-200 transition-all flex items-center gap-2 active:scale-[0.98]"
          >
            Continuar
            <ArrowRight className="w-5 h-5" />
          </button>
        </div>
      </form>
    </div>
  );
};

export default ContextForm;

import { GoogleGenAI } from "@google/genai";
import { DocType, TeacherContext, CurriculumAnalysis } from "../types";

const getAiClient = () => {
  const manualKey = localStorage.getItem('GEMINI_API_KEY');
  const apiKey = manualKey || process.env.API_KEY;

  if (!apiKey) {
    throw new Error("No se ha configurado ninguna API KEY. Por favor, configúrala en el icono de ajustes.");
  }

  return new GoogleGenAI({ apiKey });
};

const SYSTEM_INSTRUCTION = `
Eres un experto pedagogo y jefe de departamento con amplia experiencia en normativa educativa (LOMLOE) y diseño curricular.
Tu objetivo es redactar documentos oficiales precisos basándote en el currículum oficial (PDF) y el contexto proporcionado.
Debes seguir estrictamente la estructura de Markdown solicitada para que el sistema pueda procesar los campos.
Usa un lenguaje técnico, inclusivo y profesional.
IMPORTANTE: Debes escribir el documento ÚNICA Y EXCLUSIVAMENTE en el idioma solicitado por el usuario.
`;

export const analyzePdfStructure = async (pdfBase64: string): Promise<CurriculumAnalysis> => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: `Analiza este PDF del currículum oficial.
          Extrae la siguiente información estructurada en JSON:
          1. "subject": Nombre probable de la Asignatura (ej: Matemáticas).
          2. "grade": Determina a qué curso pertenece el documento. DEBE ser estrictamente uno de estos valores: "1ºESO", "2ºESO", "3ºESO", "4ºESO", "1º Bachiller", "2º Bachiller". 
             - Si el PDF describe varios cursos o la etapa completa, devuelve "múltiple".
             - Si no puedes determinarlo con seguridad, devuelve "".
          3. "competencies": Una lista (array de strings) de las Competencias Específicas detectadas. Cada string DEBE empezar con su código (ej: "CE1: [Título]").
          4. "blocks": Una lista (array de strings) de los Bloques de Saberes Básicos. Cada string DEBE empezar con "Bloque X: [Nombre]".

          Devuelve SOLO el JSON raw.` }
        ]
      },
      config: { 
        responseMimeType: "application/json" 
      }
    });

    let text = response.text || "{}";
    const parsed = JSON.parse(text);

    // Normalizar grado: si es 'múltiple' devolvemos vacío para que el usuario elija en el desplegable obligatorio
    const finalGrade = (parsed.grade === "múltiple" || !parsed.grade) ? "" : parsed.grade;

    return {
      subject: parsed.subject || "",
      grade: finalGrade,
      competencies: parsed.competencies || [],
      blocks: parsed.blocks || []
    };
  } catch (e) {
    console.error("Error analyzing PDF", e);
    return { subject: "", grade: "", competencies: [], blocks: [] };
  }
};

export const generateEducationalDocument = async (
  pdfBase64: string,
  context: TeacherContext,
  docType: DocType
): Promise<string> => {
  const ai = getAiClient();
  let prompt = "";
  const needsString = [...context.selectedNeeds, context.otherNeeds].filter(Boolean).join(", ");
  const methodologiesString = context.methodologyPreference.join(", ");
  const langInstruction = `EL DOCUMENTO DEBE ESTAR ESCRITO ÍNTEGRAMENTE EN: ${context.language}.`;

  if (docType === DocType.PROPUESTA) {
    prompt = `
      ${langInstruction}
      Genera una **PROPUESTA PEDAGÓGICA DE DEPARTAMENTO**.
      Usa exactamente estos encabezados de nivel 2:

      # PROPUESTA PEDAGÓGICA: ${context.subject}
      ## 1. Concreción Curricular
      Detalla competencias específicas y criterios del PDF vinculados a ${context.gradeLevel}.
      ## 2. Metodología y Estrategias
      Basadas en: ${methodologiesString}.
      ## 3. Evaluación
      Instrumentos, criterios de calificación y temporalización (basado en ${context.weeklyHours}h/semana).
      ## 4. Atención a la Diversidad
      Medidas específicas para: ${needsString}.
    `;
  } else {
    // Construir instrucciones para las ideas de las SAs
    let ideasPrompt = "";
    if (!context.generateFullCourse && context.saIdeas.length > 0) {
      ideasPrompt = "\n\nIMPORTANTE: Ten en cuenta estas propuestas específicas del usuario para cada SdA:\n";
      context.saIdeas.forEach((idea, idx) => {
        if (idea.trim()) {
          ideasPrompt += `- SdA número ${idx + 1}: ${idea.trim()}\n`;
        }
      });
    }

    prompt = `
      ${langInstruction}
      Genera ${context.numberOfSAs} **SITUACIONES DE APRENDIZAJE** detalladas para ${context.subject} (${context.gradeLevel}).
      ${ideasPrompt}

      PARA CADA SITUACIÓN DE APRENDIZAJE, debes usar EXACTAMENTE esta estructura:

      ## SITUACIÓN DE APRENDIZAJE: [Título Sugerente]

      **Contexto:**
      | Personal | Educativo | Social | Profesional |
      | :--- | :--- | :--- | :--- |
      | [Descripción] | [Descripción] | [Descripción] | [Descripción] |

      **Descripción / Justificación:**
      [Justificación pedagógica]

      **Relación con los retos del s.XXI y los ODS:**
      [Vinculación con ODS]

      **Competencias Específicas y Criterios de Evaluación vinculados:**
      [Cita competencias del PDF]

      **Saberes Básicos:**
      [Saberes del PDF]

      **Organización:**
      Genera una tabla con al menos 3 filas (Actividad 1, Actividad 2, Actividad 3).
      | Sequenciació d'activitats | Organització dels espais | Distribució del tempi | Recursos i materials | Mesures de respuesta educativa per a la inclusió |
      | :--- | :--- | :--- | :--- | :--- |
      | **Actividad 1:** [Nombre] | [Espacio] | [Tiempo] | [Recursos] | [Medidas] |
      | **Actividad 2:** [Nombre] | [Espacio] | [Tiempo] | [Recursos] | [Medidas] |
      | **Actividad 3:** [Nombre] | [Espacio] | [Tiempo] | [Recursos] | [Medidas] |

      **Instrumentos de recogida de información:**
      [Lista de instrumentos]
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: pdfBase64 } },
          { text: prompt },
        ],
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    return response.text || "Error en generación.";
  } catch (error) {
    console.error(error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { TeacherContext, CurriculumAnalysis } from '../types';
import { ArrowRight, CheckSquare, Square, Clock, BookOpen, Users, Globe, Briefcase, AlertCircle, RefreshCw, GraduationCap, Lightbulb } from 'lucide-react';
import CurricularReference from './CurricularReference';

interface ContextFormProps {
  initialData: TeacherContext;
  analysisData: CurriculumAnalysis | null;
  onReAnalyze: () => void;
  onSubmit: (data: TeacherContext) => void;
}

const COMMON_NEEDS = [
  "Alumnado TDAH",
  "Altas Capacidades",
  "Dislexia / DEA",
  "Medidas Nivel II (Apoyo ordinario)",
  "Medidas Nivel III (Apoyo específico)",
  "Desconocimiento del idioma",
  "Problemas de conducta",
  "Discapacidad motora"
];

const METHODOLOGIES = [
  "Aprendizaje Basado en Proyectos (ABP)",
  "Flipped Classroom",
  "Gamificación",
  "Aprendizaje Cooperativo",
  "Instrucción Directa y Práctica",
  "Aprendizaje Basado en Retos",
  "Aprendizaje Servicio (ApS)",
  "Design Thinking"
];

const GRADE_LEVELS = [
  "1ºESO",
  "2ºESO",
  "3ºESO",
  "4ºESO",
  "1º Bachiller",
  "2º Bachiller"
];

const ContextForm: React.FC<ContextFormProps> = ({ initialData, analysisData, onReAnalyze, onSubmit }) => {
  const [formData, setFormData] = useState<TeacherContext>(initialData);

  // Ya no marcamos como incompleto si falta el grado, ya que es normal si el PDF es multi-nivel
  const isAnalysisIncomplete = !analysisData || 
    !analysisData.subject || 
    analysisData.competencies.length === 0 || 
    analysisData.blocks.length === 0;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'numberOfSAs') {
      const num = parseInt(value) || 1;
      const clampedNum = Math.min(Math.max(num, 1), 15);

      setFormData(prev => {
        const newIdeas = [...prev.saIdeas];
        if (newIdeas.length < clampedNum) {
          while (newIdeas.length < clampedNum) newIdeas.push('');
        } else {
          newIdeas.length = clampedNum;
        }
        return { ...prev, numberOfSAs: clampedNum, saIdeas: newIdeas };
      });
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleIdeaChange = (index: number, value: string) => {
    setFormData(prev => {
      const newIdeas = [...prev.saIdeas];
      newIdeas[index] = value;
      return { ...prev, saIdeas: newIdeas };
    });
  };

  const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, checked } = e.target;
    if (name === 'generateFullCourse') {
      setFormData(prev => ({ ...prev, generateFullCourse: checked }));
    }
  };

  const handleNeedToggle = (need: string) => {
    setFormData(prev => {
      const currentNeeds = prev.selectedNeeds || [];
      if (currentNeeds.includes(need)) {
        return { ...prev, selectedNeeds: currentNeeds.filter(n => n !== need) };
