        {/* Contenedor del documento - Optimizado para PDF */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[70vh] relative">
          {isRefining && (
            <div className="absolute inset-0 z-50 bg-white/80 backdrop-blur-[2px] flex flex-col items-center justify-center animate-fade-in">
