import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import FileUpload from './components/FileUpload';
import ContextForm from './components/ContextForm';
import DocTypeSelector from './components/DocTypeSelector';
import Editor from './components/Editor';
import { AppStep, DocType, TeacherContext, CurriculumAnalysis } from './types';
import { generateEducationalDocument, analyzePdfStructure, refineDocument } from './services/geminiService';
import { Loader2, AlertCircle, FileSearch, Key } from 'lucide-react';

const initialContext: TeacherContext = {
  subject: '',
  department: '',
  gradeLevel: '',
  weeklyHours: 3,
  language: 'Castellano',
  selectedNeeds: [],
  otherNeeds: '',
  methodologyPreference: ['Aprendizaje Basado en Proyectos (ABP)'],
  generateFullCourse: false,
  numberOfSAs: 2,
  saIdeas: ['', ''],
};

export default function App() {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [pdfBase64, setPdfBase64] = useState<string>('');
  const [pdfName, setPdfName] = useState<string>('');
  const [context, setContext] = useState<TeacherContext>(initialContext);
  const [analysisData, setAnalysisData] = useState<CurriculumAnalysis | null>(null);
  const [resultContent, setResultContent] = useState<string>('');
  const [currentDocType, setCurrentDocType] = useState<DocType | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasApiKey, setHasApiKey] = useState(true);

  useEffect(() => {
    const checkKey = () => {
      const key = localStorage.getItem('GEMINI_API_KEY') || process.env.API_KEY;
      setHasApiKey(!!key);
    };
    checkKey();
    window.addEventListener('storage', checkKey);
    return () => window.removeEventListener('storage', checkKey);
  }, []);

  const performAnalysis = async (base64: string) => {
    if (!hasApiKey) return;
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzePdfStructure(base64);
      setAnalysisData(analysis);

      setContext(prev => ({
        ...prev,
        subject: analysis.subject || prev.subject,
        gradeLevel: analysis.grade || prev.gradeLevel
      }));
      setStep(AppStep.CONTEXT);
    } catch (err: any) {
      setError("Error al analizar el PDF. Por favor, verifica tu clave de API en la configuración.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleFileSelect = async (base64: string, name: string) => {
    if (base64) {
      setPdfBase64(base64);
      setPdfName(name);
      await performAnalysis(base64);
    }
  };

  const handleContextSubmit = (data: TeacherContext) => {
    setContext(data);
    setStep(AppStep.SELECT_TYPE);
  };

  const handleDocTypeSelect = async (type: DocType) => {
    setCurrentDocType(type);
    setStep(AppStep.GENERATING);
    setError(null);

    try {
      const content = await generateEducationalDocument(pdfBase64, context, type);
      setResultContent(content);
      setStep(AppStep.EDITOR);
    } catch (err: any) {
      setError(err.message || "Error al generar el documento.");
      setStep(AppStep.SELECT_TYPE);
    }
  };

  const handleRefine = async (feedback: string): Promise<string> => {
    if (!currentDocType) throw new Error("Tipo de documento no definido.");

    const newContent = await refineDocument(
      pdfBase64,
      context,
      currentDocType,
      resultContent,
      feedback
    );

    setResultContent(newContent);
    return newContent;
  };

  const handleRestart = () => {
    setStep(AppStep.UPLOAD);
    setPdfBase64('');
    setResultContent('');
    setAnalysisData(null);
    setError(null);
  };

  const AnalysisLoadingView = (
    <div className="py-20 flex flex-col items-center text-center bg-white rounded-2xl border border-slate-200 shadow-sm animate-fade-in">
      <div className="relative mb-6">
        <div className="absolute inset-0 bg-indigo-100 rounded-full animate-ping opacity-25"></div>
        <div className="relative bg-indigo-50 p-6 rounded-full">
          <FileSearch className="w-12 h-12 text-indigo-600" />
        </div>
      </div>
      <h3 className="text-xl font-bold text-slate-800">Analizando currículum...</h3>
      <p className="text-slate-500 max-w-sm mx-auto mt-2 leading-relaxed">
        Estamos extrayendo competencias y saberes del PDF para automatizar tu planificación.
      </p>
      <div className="mt-8 flex items-center gap-2 text-indigo-600 font-medium text-sm">
        <Loader2 className="w-4 h-4 animate-spin" />
        Procesando con Gemini AI
      </div>
    </div>
  );

  return (
    <Layout>
      <div className="w-full mx-auto">
        {!hasApiKey && step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto mb-8 bg-rose-50 border-2 border-rose-200 p-6 rounded-2xl flex flex-col items-center gap-4 text-rose-800 animate-fade-in">
            <div className="bg-rose-100 p-4 rounded-full">
              <Key className="w-8 h-8 text-rose-600" />
            </div>
            <div className="text-center">
              <h3 className="text-lg font-bold">API KEY no detectada</h3>
              <p className="text-sm mt-1 opacity-90">
                Para usar este asistente, necesitas configurar tu propia clave de Google Gemini (es gratuita).
              </p>
            </div>
            <button 
              onClick={() => {
                const btn = document.querySelector('[title="Configuración de API"]') as HTMLButtonElement;
                btn?.click();
              }}
              className="bg-rose-600 hover:bg-rose-700 text-white font-bold py-2 px-6 rounded-lg shadow-lg transition-all active:scale-95 text-sm"
            >
              Configurar API Key ahora
            </button>
          </div>
        )}

        {error && (
          <div className="max-w-4xl mx-auto mb-6 bg-red-50 border border-red-200 p-4 rounded-xl flex items-center gap-3 text-red-700 animate-shake">
            <AlertCircle className="w-5 h-5 shrink-0" />
            <p className="text-sm font-medium">{error}</p>
          </div>
        )}

        <div className="max-w-4xl mx-auto mb-8 flex items-center justify-center gap-4 text-sm font-bold print:hidden">
          <div className={`flex flex-col items-center gap-1 ${step === AppStep.UPLOAD ? 'text-indigo-600' : 'text-slate-300'}`}>
            <span className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${step === AppStep.UPLOAD ? 'border-indigo-600' : 'border-slate-200'}`}>1</span>
            <span className="hidden sm:inline">Subir</span>
          </div>
          <div className="w-8 h-[2px] bg-slate-200 mb-6"></div>
          <div className={`flex flex-col items-center gap-1 ${step === AppStep.CONTEXT ? 'text-indigo-600' : 'text-slate-300'}`}>
            <span className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${step === AppStep.CONTEXT ? 'border-indigo-600' : 'border-slate-200'}`}>2</span>
            <span className="hidden sm:inline">Contexto</span>
          </div>
          <div className="w-8 h-[2px] bg-slate-200 mb-6"></div>
          <div className={`flex flex-col items-center gap-1 ${step === AppStep.SELECT_TYPE ? 'text-indigo-600' : 'text-slate-300'}`}>
            <span className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${step === AppStep.SELECT_TYPE ? 'border-indigo-600' : 'border-slate-200'}`}>3</span>
            <span className="hidden sm:inline">Tipo</span>
          </div>
          <div className="w-8 h-[2px] bg-slate-200 mb-6"></div>
          <div className={`flex flex-col items-center gap-1 ${step === AppStep.EDITOR ? 'text-indigo-600' : 'text-slate-300'}`}>
            <span className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${step === AppStep.EDITOR ? 'border-indigo-600' : 'border-slate-200'}`}>4</span>
            <span className="hidden sm:inline">Resultado</span>
          </div>
        </div>

        <div className={step === AppStep.EDITOR ? 'w-full' : 'max-w-4xl mx-auto'}>
          {isAnalyzing ? (
            AnalysisLoadingView
          ) : (
            <>
              {step === AppStep.UPLOAD && <FileUpload onFileSelect={handleFileSelect} disabled={!hasApiKey} />}
              {step === AppStep.CONTEXT && (
                <ContextForm 
                  initialData={context} 
                  analysisData={analysisData} 
                  onReAnalyze={() => performAnalysis(pdfBase64)} 
                  onSubmit={handleContextSubmit} 
                />
              )}
              {step === AppStep.SELECT_TYPE && <DocTypeSelector onSelect={handleDocTypeSelect} />}
              {step === AppStep.GENERATING && (
                <div className="py-20 flex flex-col items-center text-center bg-white rounded-2xl border border-slate-200 shadow-sm animate-fade-in">
                  <Loader2 className="w-12 h-12 text-indigo-600 animate-spin mb-4" />
                  <h3 className="text-xl font-bold">Generando contenido pedagógico...</h3>
                  <p className="text-slate-500 max-w-sm mx-auto mt-2 leading-relaxed">
                    Redactando {currentDocType === DocType.PROPUESTA ? 'tu propuesta de departamento' : 'tus situaciones de aprendizaje'} con rigor curricular.
                  </p>
                </div>
              )}
              {step === AppStep.EDITOR && (
                <Editor 
                  initialContent={resultContent} 
                  docTitle={currentDocType === DocType.PROPUESTA ? 'Propuesta Pedagógica' : 'Situaciones de Aprendizaje'} 
                  onRestart={handleRestart} 
                  analysisData={analysisData} 
                  onRefine={handleRefine}
                  language={context.language}
                />
              )}
            </>
          )}
        </div>
      </div>
    </Layout>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Download, Edit3, ArrowLeft, Save, FileText, ChevronDown, ChevronUp, Layers, Type, LayoutTemplate, FileJson, FileType, Printer, Plus, Trash2, Send, MessageSquare, Loader2, Sparkles, User, Info } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { CurriculumAnalysis } from '../types';
import CurricularReference from './CurricularReference';

interface EditorProps {
  initialContent: string;
  docTitle: string;
  onRestart: () => void;
  analysisData: CurriculumAnalysis | null;
  onRefine: (feedback: string) => Promise<string>;
  language?: string;
  gradeLevel?: string;
  subject?: string;
  department?: string;
}

interface DocSection {
  id: number;
  title: string;
  content: string; 
  level: number; 
}

interface ActivityRow {
  sequencing: string;
  spaces: string;
  time: string;
  resources: string;
  inclusion: string;
}

interface SAStructure {
  contextPersonal: string;
  contextEducativo: string;
  contextSocial: string;
  contextProfesional: string;
  justification: string;
  ods: string;
  competencies: string;
  knowledge: string;
  activities: ActivityRow[];
  instruments: string;
}

const Editor: React.FC<EditorProps> = ({ 
  initialContent, 
  docTitle, 
  onRestart, 
  analysisData, 
  onRefine, 
  language = 'Castellano',
  gradeLevel = '',
  subject = '',
  department = ''
}) => {
  const [content, setContent] = useState(initialContent);
  const [teacherName, setTeacherName] = useState(localStorage.getItem('TEACHER_NAME') || '');
  const [mode, setMode] = useState<'edit' | 'preview'>('preview');
  const [sections, setSections] = useState<DocSection[]>([]);
  const [expandedSection, setExpandedSection] = useState<number | null>(null);
  const [chatInput, setChatInput] = useState('');
  const [isRefining, setIsRefining] = useState(false);
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const previewRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setContent(initialContent);
  }, [initialContent]);

  useEffect(() => {
    localStorage.setItem('TEACHER_NAME', teacherName);
  }, [teacherName]);

  useEffect(() => {
    if (mode === 'edit') {
      const parsed = parseMarkdownToSections(content);
      setSections(parsed);
      if (parsed.length > 0) setExpandedSection(parsed[0].id);
    }
  }, [mode, content]);

  const parseMarkdownToSections = (md: string): DocSection[] => {
    const lines = md.split('\n');
    const result: DocSection[] = [];
    let currentSection: DocSection | null = null;
    let currentBuffer: string[] = [];
    let idCounter = 0;

    const pushCurrent = () => {
      if (currentSection) {
        currentSection.content = currentBuffer.join('\n').trim();
        result.push(currentSection);
      } else if (currentBuffer.length > 0 && currentBuffer.some(l => l.trim() !== '')) {
        result.push({
          id: idCounter++,
          title: "Portada / Introducción",
          content: currentBuffer.join('\n').trim(),
          level: 0
        });
      }
      currentBuffer = [];
    };

    const headerRegex = /^(#{1,6})\s+(.*)$/;

    for (const line of lines) {
      const match = line.match(headerRegex);
      if (match) {
        pushCurrent();
        const level = match[1].length;
        const title = match[2];
        currentSection = {
          id: idCounter++,
          title: title,
          content: "",
          level: level
        };
      } else {
        currentBuffer.push(line);
      }
    }
    pushCurrent();
    return result;
  };

  const saveSectionsToContent = () => {
    const newContent = sections.map(s => {
      if (s.level === 0) return s.content;
      return `${'#'.repeat(s.level)} ${s.title}\n\n${s.content}`;
    }).join('\n\n');

    setContent(newContent);
    setMode('preview');
  };

  const handleRefineSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isRefining) return;
    setIsRefining(true);
    const feedback = chatInput;
    setChatInput('');
    try {
      const newContent = await onRefine(feedback);
      setContent(newContent);
      setMode('preview');
    } catch (err) {
      alert("Error al intentar ajustar el documento.");
    } finally {
      setIsRefining(false);
    }
  };

  const downloadFile = (data: Blob, filename: string) => {
    const element = document.createElement("a");
    element.href = URL.createObjectURL(data);
    element.download = filename;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const handleDownloadMD = () => {
    const blob = new Blob([content], {type: 'text/markdown'});
    downloadFile(blob, `${docTitle.replace(/\s+/g, '_')}.md`);
  };

  const handleDownloadODT = () => {
    const headerBlock = `
      <div style="border-bottom: 1px solid #64748b; padding-bottom: 5px; margin-bottom: 20px; font-size: 10pt; color: #64748b;">
        <table style="width: 100%; border: none;">
          <tr>
            <td style="border: none; text-align: left;"><strong>Profesor:</strong> ${teacherName || '---'}</td>
            <td style="border: none; text-align: right;"><strong>Asignatura:</strong> ${subject} (${gradeLevel})</td>
          </tr>
          <tr>
            <td style="border: none; text-align: left;"><strong>Departamento:</strong> ${department}</td>
            <td style="border: none; text-align: right;"><strong>EduPlanner AI</strong></td>
          </tr>
        </table>
      </div>
    `;

    const htmlString = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <title>${docTitle}</title>
        <style>
          @page Section1 {
            size: 29.7cm 21.0cm;
            margin: 1.5cm;
            mso-page-orientation: landscape;
            @bottom-right {
              content: "Página " counter(page);
            }
          }
          div.Section1 { page: Section1; }
          body { font-family: 'Arial', sans-serif; line-height: 1.6; color: #1e293b; }
          table { border-collapse: collapse; width: 100%; margin: 20px 0; }
          th, td { border: 1px solid #94a3b8; padding: 10px; text-align: left; font-size: 9pt; vertical-align: top; }
          th { background-color: #f1f5f9; font-weight: bold; }
          h1 { font-size: 24pt; color: #0f172a; margin-bottom: 15pt; text-align: center; }
          h2 { font-size: 18pt; color: #1e293b; border-bottom: 1px solid #cbd5e1; page-break-before: always; }
          p { margin-bottom: 10pt; text-align: justify; }
        </style>
      </head>
      <body>
        <div class="Section1">
          ${headerBlock}
          ${previewRef.current?.innerHTML || ''}
        </div>
      </body>
      </html>
    `;
    const blob = new Blob([htmlString], {type: 'application/msword'});
    downloadFile(blob, `${docTitle.replace(/\s+/g, '_')}.doc`);
  };

  const handleDownloadPDF = () => {
    setMode('preview');
    setIsGeneratingPDF(true);

    setTimeout(() => {
      const element = previewRef.current;
      if (!element) {
        setIsGeneratingPDF(false);
        return;
      }

      element.classList.add('pdf-export-mode');

      // Inyectar header/footer dinámico
      const headerHtml = `
        <div class="pdf-header only-print">
          <div><strong>Docente:</strong> ${teacherName || '---'} | <strong>Dpto:</strong> ${department}</div>
          <div><strong>${subject}</strong> (${gradeLevel})</div>
        </div>
      `;
      const footerHtml = `
        <div class="pdf-footer only-print">
          <span>EduPlanner AI - Planificación Docente</span>
        </div>
      `;

      // Para html2pdf, la mejor forma de repetir headers es con un wrapper de tabla real
      const originalHtml = element.innerHTML;
      element.innerHTML = `
        <table style="width: 100%; border: none; border-collapse: collapse;">
          <thead>
            <tr><td style="border: none; padding: 0;">
              <div style="height: 50px; border-bottom: 1px solid #cbd5e1; margin-bottom: 20px; display: flex; align-items: center; justify-content: space-between; font-size: 10px; color: #64748b; font-family: sans-serif;">
                <span><strong>Profesor:</strong> ${teacherName || 'No especificado'} | <strong>Dpto:</strong> ${department}</span>
                <span><strong>${subject}</strong> (${gradeLevel})</span>
              </div>
            </td></tr>
          </thead>
          <tbody>
            <tr><td style="border: none; padding: 0;">
              <div class="pdf-content-body">${originalHtml}</div>
            </td></tr>
          </tbody>
          <tfoot>
            <tr><td style="border: none; padding: 0;">
              <div style="height: 30px; border-top: 1px solid #e2e8f0; margin-top: 20px; display: flex; align-items: center; justify-content: flex-end; font-size: 10px; color: #94a3b8; font-family: sans-serif;">
                <span>EduPlanner AI - Página Generada</span>
              </div>
            </td></tr>
          </tfoot>
        </table>
      `;

      const opt = {
        margin:       [15, 15, 15, 15],
        filename:     `${docTitle.replace(/\s+/g, '_')}.pdf`,
        image:        { type: 'jpeg', quality: 0.98 },
        html2canvas:  { 
          scale: 2, 
          useCORS: true,
          scrollY: 0,
          scrollX: 0,
          letterRendering: true
        },
        jsPDF:        { unit: 'mm', format: 'a4', orientation: 'landscape' },
        pagebreak:    { mode: ['css', 'legacy'], before: 'h2' }
      };

      // @ts-ignore
      window.html2pdf()
        .from(element)
        .set(opt)
        .save()
        .then(() => {
          element.innerHTML = originalHtml;
          element.classList.remove('pdf-export-mode');
          setIsGeneratingPDF(false);
        })
        .catch((err: any) => {
          element.innerHTML = originalHtml;
          element.classList.remove('pdf-export-mode');
          setIsGeneratingPDF(false);
          alert("Error generando PDF.");
        });
    }, 800);
  };

  return (
